frappe.ui.form.on("Travel Request1", {


travel_type: function(frm) {
    if (frm.doc.travel_type === "International") {
        frm.set_df_property("passport_number", "reqd", 1);
    } else {
        frm.set_df_property("passport_number", "reqd", 0);
    }
},

employee: function(frm) {
    if (frm.doc.employee) {
        frappe.db.get_doc("Employee", frm.doc.employee)
            .then(doc => {
                frm.set_value("passport_number", doc.passport_number);
                frm.set_value("travel_grade", doc.travel_grade);
                frm.set_value("department", doc.department);
            });
    }
}

});

frappe.ui.form.on("Travel Expense Item", {


amount: function(frm) {
    calculate_total(frm);
},

expenses_remove: function(frm) {
    calculate_total(frm);
}


});

function calculate_total(frm) {
let total = 0;


(frm.doc.expenses || []).forEach(row => {
    total += row.amount || 0;
});

frm.set_value("total_estimated_amount", total);


}
